#include<cstdio>
#include<vector>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL;
#define int LL
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
inline int read()
{
	int res(0);char ch(getchar());while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void printLL(const LL &p){if(p>9ll)printLL(p/10ll);putchar(p%10ll+'0');}
inline void print(const int &p,const char &ch='\n'){printLL(p);putchar(ch);}
const int N=5e5+10; int n;  LL ans[N];
struct TRI
{
	int l,r;LL w;inline bool operator<(const TRI &Q)const {return w<Q.w;}
	inline TRI(const int &ll=0,const int &rr=0,const LL &ww=0){l=ll;r=rr;w=ww;}
};
struct QRY{int l,r,x,y,idx;inline QRY(const int &ll=0,const int &rr=0,const int &xx=0,const int &yy=0,const int &I=0){l=ll;r=rr;x=xx;y=yy;idx=I;}}tmp[N];
std:: vector<TRI> OP[N];std::vector<QRY> QE[N];
namespace SegX
{
	LL cmx[N<<1],hmx[N<<1],ctg[N<<1],htg[N<<1];bool tg[N<<1];
	inline void Add(const int &x,const LL &c,const LL &h){chkmax(htg[x],ctg[x]+h);chkmax(hmx[x],cmx[x]+h);ctg[x]+=c;cmx[x]+=c;}
	inline void Bac(const int &x){Add(x<<1,ctg[x],htg[x]);Add(x<<1|1,ctg[x],htg[x]);ctg[x]=htg[x]=0;hmx[x]=cmx[x];tg[x]=true;}
	inline void update(const int &x){cmx[x]=max(cmx[x<<1],cmx[x<<1|1]);hmx[x]=max(hmx[x<<1],hmx[x<<1|1]);}
	inline void pushdown(const int &x){if(tg[x]){Bac(x<<1);Bac(x<<1|1);tg[x]=false;}Add(x<<1,ctg[x],htg[x]);Add(x<<1|1,ctg[x],htg[x]);ctg[x]=htg[x]=0;}
	inline void add(const int &ql,const int &qr,const LL &w,const int &l=1,const int &r=n,const int &cur=1)
	{
		if(ql<=l&&r<=qr)return Add(cur,w,w);pushdown(cur);const int &mid=(l+r)>>1;
		if(ql<=mid)add(ql,qr,w,l,mid,cur<<1);if(qr>mid)add(ql,qr,w,mid+1,r,cur<<1|1);update(cur);
	}
	inline LL qry(const int &ql,const int &qr,const int &l=1,const int &r=n,const int &cur=1)
	{
		if(ql<=l&&r<=qr)return hmx[cur];pushdown(cur);const int &mid=(l+r)>>1;LL w=0;
		if(ql<=mid)w=qry(ql,qr,l,mid,cur<<1);if(qr>mid)chkmax(w,qry(ql,qr,mid+1,r,cur<<1|1));return w;
	}
}
namespace SegY
{
	using SegX::add;using SegX::qry;using SegX::Bac;
	inline void ins(const QRY &Q,const int &l=1,const int &r=n,const int &x=1)
	{
		const int &mid=(l+r)>>1;if(Q.l<=mid+1&&mid<=Q.r)return QE[x].push_back(Q),void();
		if(Q.r<=mid)return ins(Q,l,mid,x<<1);if(Q.l>mid)return ins(Q,mid+1,r,x<<1|1);QE[x].push_back(Q);
	}
	inline void Opt(const int &x,const bool &op)
	{
		if(op){for(TRI v:OP[x])add(v.l,v.r,v.w);}
		else{for(unsigned i=OP[x].size()-1;~i;--i)add(OP[x][i].l,OP[x][i].r,-OP[x][i].w);}
	}
	inline bool cmp1(const QRY&x,const QRY&y){return x.r<y.r;}
	inline bool cmp2(const QRY&x,const QRY&y){return x.l>y.l;}
	inline void getAns(const int &l=1,const int &r=n,const int &cur=1)
	{
		const int &mid=(l+r)>>1;rep(l,mid,i)Opt(i,true);
		LL cnt=0,p=1;for(QRY v: QE[cur])tmp[++cnt]=v;
		std::sort(tmp+1,tmp+cnt+1,cmp1);while(p<=cnt&&tmp[p].r==mid)++p;
		rep(mid+1,r,i){Opt(i,true);if(i==mid+1)Bac(1);while(tmp[p].r==i&&p<=cnt){chkmax(ans[tmp[p].idx],qry(tmp[p].x,tmp[p].y));++p;}}
		drep(r,mid+1,i)Opt(i,false);if(l!=r)getAns(mid+1,r,cur<<1|1);
		cnt=0;p=1; for(QRY v: QE[cur]){tmp[++cnt]=v;} std:: sort(tmp+1,tmp+cnt+1,cmp2);while(p<=cnt&&tmp[p].l==mid+1)++p;
		drep(mid,l,i){if(i==mid)Bac(1);while(tmp[p].l==i&&p<=cnt){chkmax(ans[tmp[p].idx],qry(tmp[p].x,tmp[p].y));++p;}Opt(i,false);}
		if(l!=r)getAns(l,mid,cur<<1);
	}
}
using SegY::ins;using SegY::getAns;
signed main()
{
//	FIN("data.in");FOUT("mine.out");
	n=read();int m=read(),Q=read();while(m--)
	{
		int l=read(),x=read(),r=read(),y=read();LL w=read();
		OP[l].push_back(TRI(x,y,w));OP[r+1].push_back(TRI(x,y,-w));
	}
	rep(1,Q,i){int l=read(),x=read(),r=read(),y=read();ins(QRY(l,r,x,y,i));}
	rep(1,n,i)std:: sort(OP[i].begin(),OP[i].end()); getAns();
	rep(1,Q,i)print(ans[i]);putchar('\n');return 0;
}
